// W4 — Build Input
// Edita los valores de `input` para probar distintos payloads.
//
// CONVENCIONES DEV:
//   - canal y id_evento solo se usan para id_evento_dev (trazabilidad de pruebas)
//   - W4 NO genera idempotency_key. La función confirmar_reserva() no la espera.
//     Tampoco implementa idempotent_match: re-confirmar una pre-reserva ya
//     convertida devuelve error 'estado_invalido'.
//   - source_event fijo: "n8n_w04_confirmar_reserva_manual"
//
// CAMINOS DE CONFIRMACIÓN:
//   - Estricto (default, permitir_pago_en_revision=false):
//     Requiere AL MENOS un pago en estado 'confirmado' para la pre-reserva.
//   - Combinado (permitir_pago_en_revision=true Y validado_por != null):
//     Si no hay pago 'confirmado', toma el más reciente 'en_revision' y lo
//     confirma en el mismo flujo (con validado_por = quien aprueba).
//
// DEFAULTS PARA HAPPY PATH DEV (sobre pre-reserva 25 cuyo pago 11 está en_revision):
//   - permitir_pago_en_revision: true
//   - validado_por: "rodrigo_manual"

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  // Identificación del evento (solo para trazabilidad de pruebas)
  canal: "manual_dev",
  id_evento: "test_w04_001",

  // Obligatorio
  id_pre_reserva: 25,

  // Camino combinado (necesario en DEV: pago 11 está en en_revision)
  permitir_pago_en_revision: true,
  validado_por: "rodrigo_manual",

  // Datos operativos (se copian a la nueva reserva)
  encargado_semana: "rodrigo",
  created_by: "manual_dev"
};
// =============================================

return [{ json: input }];

// W4 — Build Payload
// Toma el input editable de Build Input y construye:
//   1. source_event (convención 6C v1.2 Sección 5.5):
//        n8n_w04_confirmar_reserva_manual
//   2. id_evento_dev: solo para trazabilidad de pruebas en el wrapper
//      (NO se manda a la función SQL).
//   3. payload JSONB según contrato de confirmar_reserva(jsonb).
//
// CONTRATO PAYLOAD:
//   Obligatorios: id_pre_reserva, source_event
//   Opcionales:   permitir_pago_en_revision (default false),
//                 validado_por (requerido si permitir_pago_en_revision=true),
//                 encargado_semana, created_by
//
// W4 NO genera idempotency_key. La función no la espera ni implementa
// idempotent_match (a diferencia de crear_prereserva).
//
// NORMALIZACIÓN DEFENSIVA (continuación de patrón W3):
// Aplicamos nv() a todos los campos opcionales y a id_pre_reserva.
// La función confirmar_reserva() tampoco aplica NULLIF en sus extracts;
// mientras el hardening SQL no se aplique (ver Pendiente_pre_produccion.md),
// la defensa queda en n8n.

const input = $input.first().json;

const source_event = 'n8n_w04_confirmar_reserva_manual';
const id_evento_dev = `${input.canal}_${input.id_evento}`;

const nv = (v) => (v === '' || v === undefined ? null : v);

const payload = {
  // Obligatorio (defensa: si viene vacío, mandamos null para que la validación SQL rebote limpio)
  id_pre_reserva: nv(input.id_pre_reserva),

  // Camino combinado
  permitir_pago_en_revision: input.permitir_pago_en_revision,
  validado_por: nv(input.validado_por),

  // Datos operativos
  encargado_semana: nv(input.encargado_semana),
  created_by: nv(input.created_by),

  // source_event (siempre presente, definido en este nodo)
  source_event
};

return [{
  json: {
    payload,
    source_event,
    id_evento_dev,
    input  // se preserva para trazabilidad en Build Response
  }
}];

// W4 — Build Response
// Interpreta el JSONB que devuelve confirmar_reserva() y arma el wrapper externo.
//
// Contrato de salida de la función:
//   - happy: { ok: true, id_reserva, id_pre_reserva, id_huesped }
//   - error: { ok: false, error: '<codigo>', ...detalle según error }
//
// CONVENCIONES DEL WRAPPER:
//   - ok = resultado.ok
//   - error solo se llena cuando resultado.ok = false
//   - id_evento_dev para trazabilidad de pruebas
//   - result siempre lleva el JSONB completo de la función
//
// W4 NO incluye idempotency_key (no aplica) ni warning (la función no
// emite warnings — re-confirmar devuelve error "estado_invalido").

